use PDF::API2;
use Text::PDF::Tables;

# A function to parse the PDF and extract the golden text
sub extract_pdf_info {
    my ($filename) = @_;

    # A PDF document, opened for reading
    my $pdf = PDF::API2->open($filename);

    # Our search for dates, authors, and tabulated truths
    my $info = {
        date => '',
        author => '',
        tables => [],
    };

    # Loop through each page in the PDF
    for my $page (1 .. $pdf->pages) {
        my $text = $pdf->page($page)->text;
        $info->{date} = $text->search('Created:')->first if $text->search('Created:');
        $info->{author} = $text->search('Author:')->first if $text->search('Author:');

        # Extract tables if any
        my $tables = Text::PDF::Tables->new($pdf->page($page)->content);
        $info->{tables} = $tables->tables;
    }

    return $info;
}

# Usage
my $pdf_info = extract_pdf_info('sample.pdf');
print "Date: ", $pdf_info->{date}, "\n";
print "Author: ", $pdf_info->{author}, "\n";
print "Tables: ", join(", ", map { $_->as_string } @{$pdf_info->{tables}}), "\n";
